import type { Provider, ProviderCompleteOptions, ProviderResult } from '@playgenx/types';

/**
 * Deterministic provider for tests and offline development.
 *
 * Returns a fixed echo of the prompt wrapped in a stable artifact body so
 * downstream code can be exercised without network calls.
 */
export class MockProvider implements Provider {
  readonly id = 'mock';
  readonly defaultModel = 'mock-1';

  async complete(prompt: string, options?: ProviderCompleteOptions): Promise<ProviderResult> {
    const body = [
      '// Generated by MockProvider',
      `// model: ${options?.model ?? this.defaultModel}`,
      options?.maxTokens !== undefined ? `// maxTokens: ${options.maxTokens}` : '',
      options?.timeoutMs !== undefined ? `// timeoutMs: ${options.timeoutMs}` : '',
      '',
      prompt,
    ]
      .filter((line) => line !== '')
      .join('\n');
    return { body };
  }
}
